import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testIsNullStringSet_nullStringIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Using reflection to set private field nullString to null
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);
        nullStringField.set(format, null);

        assertFalse(format.isNullStringSet());
    }

    @Test
    void testIsNullStringSet_nullStringIsNotNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Using reflection to set private field nullString to a non-null value
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);
        nullStringField.set(format, "NULL");

        assertTrue(format.isNullStringSet());
    }
}
